"""Butterworth (FFT, zero-phase)."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseFilterdef _butterworth_magnitude(freqs: np.ndarray, cutoff: float,                           order: int, kind: str) -> np.ndarray:    f = np.asarray(freqs, dtype=np.float64)    if kind == "lowpass":        ratio = f / cutoff        mag = 1.0 / np.sqrt(1.0 + ratio ** (2 * order))    elif kind == "highpass":        safe_f = np.where(f > 0.0, f, np.inf)        ratio = cutoff / safe_f        mag = 1.0 / np.sqrt(1.0 + ratio ** (2 * order))        mag[f == 0.0] = 0.0    else:        raise ValueError(f"unknown kind: {kind!r}")    return magclass ButterworthFilter(BaseFilter):    name = "Butterworth (FFT, zero-phase)"    description = "Частотная маска с АЧХ Баттерворта (LP/HP), zero-phase."    params_schema = {        "kind":   {"type": "enum", "default": "lowpass",                   "choices": ["lowpass", "highpass"],                   "label": "Тип фильтра"},        "cutoff": {"type": "float", "default": 100.0,                   "min": 1.0e-6, "max": 1.0e9,                   "label": "Частота среза", "units": "Гц"},        "order":  {"type": "int", "default": 4,                   "min": 1, "max": 20,                   "label": "Порядок"},    }    def _filter(self, x: np.ndarray, p: dict, signal: Signal) -> np.ndarray:        fs = float(signal.fs)        cutoff = float(p["cutoff"])        order = int(p["order"])        kind = str(p["kind"])        nyq = 0.5 * fs        if cutoff >= nyq:            raise ValueError(                f"cutoff={cutoff} Гц должна быть строго меньше fs/2={nyq} Гц"            )        n = x.size        freqs = np.fft.rfftfreq(n, d=1.0 / fs)        spectrum = np.fft.rfft(x)        mask = _butterworth_magnitude(freqs, cutoff, order, kind)        spectrum *= mask        y = np.fft.irfft(spectrum, n=n)        return y.astype(np.float64, copy=False)